#include <iostream>#include <vector>#include <numeric>#define ll long longusing namespace std;  ll gcd(ll a, ll b) {    while (b) {        a %= b;        swap(a, b);    }    return a;}ll lcm(ll a, ll b) {    if (a == 0 || b == 0) return 0;    return (a / gcd(a, b)) * b;} int main() {    ios::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin >> t;    while (t--) {        int n;        cin >> n;        vector<ll> a(n);        for (int i = 0; i < n; i++) cin >> a[i];        vector<ll> b(n);        for (int i = 0; i < n; i++) cin >> b[i];        int operations = 0;        for (int i = 0; i < n; i++) {        ll required_lcm;                    if (i == 0) {            required_lcm = gcd(a[i], a[i + 1]);        } else if (i == n - 1) {            required_lcm = gcd(a[i - 1], a[i]);        } else {            ll left_gcd = gcd(a[i - 1], a[i]);            ll right_gcd = gcd(a[i], a[i + 1]);            required_lcm = lcm(left_gcd, right_gcd);            }        if (required_lcm < a[i]) {            operations++;            }        }        cout << operations << "\n";    }    return 0;}